@@ -769,6 +769,9 @@ Instruction *InstCombinerImpl::visitFMul(BinaryOperator &I) {
   if (Instruction *R = foldFPSignBitOps(I))
     return R;

+  if (Instruction *R = foldFBinOpOfIntCasts(I))
+    return R;
