define double @test(i32 %a) {
  %a_and = and i32 %a, 1073741823
  %a_and_fp = sitofp i32 %a_and to double
  %res = fadd double %a_and_fp, 1.000000e+00
  ret double %res
}

define half @test_si_si_i12_add_C_fail_overflow(i12 noundef %x_in) {
